"use strict";
const mongoose = require('mongoose');
const orderSchema = new mongoose.Schema({
    orderId: { type: String, unique: true, sparse: true },
    userId: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true, index: true },
    walletType: { type: String, enum: ['spot', 'cross', 'isolated'] },
    pair: { type: String, required: true },
    side: { type: String, enum: ['buy', 'sell'], required: true },
    type: { type: String, enum: ['limit', 'market', 'stop-loss', 'stop-limit', 'oco', 'take-profit'], default: 'limit' },
    price: { type: Number },
    amount: { type: Number },
    quantity: { type: Number },
    entryPrice: { type: Number },
    lockedAmount: { type: Number },
    closePrice: { type: Number, default: 0 },
    filled: { type: Number, default: 0 },
    filledQuantity: { type: Number, default: 0 },
    stopPrice: { type: Number },
    stopLoss: { type: Number },
    takeProfit: { type: Number },
    total: { type: Number },
    exitPrice: { type: Number },
    realizedPnl: { type: Number, default: 0 },
    isDemo: { type: Boolean, default: false },
    isGenuine: { type: Boolean, default: true },
    clampedPnlPercent: { type: Number, default: 0 },
    rawPnlPercent: { type: Number, default: 0 },
    clampedPnl: { type: Number, default: 0 },
    rawPnl: { type: Number, default: 0 },
    openedAt: { type: Date, default: Date.now },
    closedAt: { type: Date },
    feeRate: { type: Number, default: 0 },
    riskParameters: { type: mongoose.Schema.Types.Mixed },
    leverage: { type: Number, default: 1 },
    positionSide: { type: String, enum: ['long', 'short'], default: 'long' },
    ocoGroupId: { type: mongoose.Schema.Types.ObjectId },
    status: {
        type: String,
        enum: ['pending', 'open', 'filled', 'cancelled', 'partially_filled', 'rejected', 'closed'],
        default: 'open',
    },
}, { timestamps: true });
module.exports = mongoose.model('Order', orderSchema);
